@ARTICLE{10.1371/journal.pbio.3003700,
	author = {Li Y and Tao M, Ibáñez CF and Xie M},
	title = {Gpc3 selectively suppresses subcutaneous adipogenesis in diet-induced obesity.},
	journal = {PLoS Biol},
	year = {2026},
	abstract = {Subcutaneous and visceral adipose depots employ distinct expansion strategies in response to dietary cues, yet the molecular regulators underlying these depot-specific adaptations remain poorly understood. Through integrated proteomic profiling of human subcutaneous and visceral adipose tissues from paired obese/non-obese donors and temporal transcriptomic analysis of mouse adipose stem and progenitor cells (ASPCs) during dietary transitions, we identified Glypican 3 (Gpc3) as an obesity-responsive gene exhibiting reciprocal expression patterns between depots. ASPC-specific Gpc3 deletion in mice amplified high-fat diet-induced weight and fat mass gain, with a selective enhancement of expansion in inguinal white adipose tissue (WAT) without affecting epididymal WAT. Mechanistically, Gpc3 loss biased ASPC fate toward adipogenesis over proliferation through depot-specific modulation of canonical Wnt signaling. These findings establish Gpc3 as a regulator for regional adipose plasticity, offering a molecular target for reprogramming pathological fat distribution in obesity and related metabolic disorders.},
	doi = {10.1371/journal.pbio.3003700},
	pmid = {41779769 [Indexed for MEDLINE]},
	note = {PMC12978566}
}

@ARTICLE{10.1096/fj.202505066R,
	author = {Song C and Chen J and Jiang X and Chen B and Pan Y and Su C and Ren J and Li X and Chen X and Wang Y and Fang X and Zhang C},
	title = {LncRNA IGF2AS Regulates Bovine Adipocyte Differentiation by Stabilizing the ILF3/FTO Complex and Activating PI3K/AKT Signaling.},
	journal = {FASEB J},
	year = {2026},
	abstract = {In our previous study, we identified IGF2AS, an antisense long noncoding RNA transcript of insulin-like growth factor 2, as a critical regulator of bovine skeletal muscle development. Subsequent investigation revealed its differential expression pattern during bovine preadipocyte differentiation, though its functional significance remained unclear. Through gain- and loss-of-function experiments, we demonstrated that IGF2AS overexpression enhances adipogenic gene expression and promotes fat deposition, while its knockdown produces opposing effects. Mechanistically, RNA-seq analysis following IGF2AS silencing revealed significant downregulation of PI3K/AKT signaling pathway components. Furthermore, RNA immunoprecipitation (RIP) and co-immunoprecipitation (Co-IP) assays identified physical interactions between IGF2AS and the ILF3/FTO protein complex, suggesting a novel regulatory axis through which IGF2AS modulates PI3K/AKT-mediated adipogenesis in bovine adipocytes. These findings not only elucidate a previously unrecognized mechanism of lncRNA-mediated fat deposition regulation but also position IGF2AS as a potential molecular target for precision breeding strategies aimed at improving beef quality.},
	doi = {10.1096/fj.202505066R},
	pmid = {41761912 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/ijms27042014,
	author = {Choi H and Lee Y and Park SH and Park J and Park KH and Baek KS and Kim J and Jung H and Kim J and Jun W},
	title = {Terminalia bellirica Extract Attenuates Fat Accumulation Through Modulation of Obesity-Related Dysmetabolism in 3T3-L1 Adipocytes and High-Fat Diet-Induced Obese Mice.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Terminalia bellirica extract (TBE) has long been utilized in Ayurvedic medicine across Indian and surrounding regions for diverse therapeutic applications. Despite its traditional prominence, systematic investigations addressing the anti-obesity efficacy and underlying mechanisms remain limited. In this study, we evaluated the anti-obesity potential of TBE using both 3T3-L1 adipocyte and high-fat diet (HFD)-induced mice model. In vitro studies using 3T3-L1 adipocytes demonstrated that TBE significantly inhibited lipid accumulation and downregulated key genes involved in adipogenesis and lipogenesis, while upregulating genes promoted lipolysis and energy metabolism. To validate these cellular effects in a physiological context, mice were randomly assigned to six groups: normal control (NC), HFD-induced obese (C), HFD with metformin (100 mg/kg b.w., PC), and HFD with TBE at 50, 100, and 200 mg/kg b.w. Consistent with the in vitro findings, TBE supplementation significantly reduced body weight gain, adipose tissue mass, and adipocyte size in HFD-induced obese mice. Taken together, these results indicate that TBE exerts anti-obesity effects through modulation of adipose tissue metabolic pathways, highlighting its therapeutic potential for obesity management.},
	doi = {10.3390/ijms27042014},
	pmid = {41752152 [Indexed for MEDLINE]},
	note = {PMC12940958}
}

@ARTICLE{10.3390/ijms27041759,
	author = {Grenet S and Ivanov S and Chinetti G},
	title = {Adipose-Tissue Macrophage Diversity and Functions.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Macrophages are the predominant immune cell type found in adipose tissue (AT). They play a critical role in tissue homeostasis and participate in metabolic regulation. In white adipose tissue (WAT), studies show that multiple macrophage subsets co-exist in the very same microenvironment. Yet these cells express selective membrane markers, allowing for identifying several well-distinguished populations. In the present review we discuss the diversity and functions of white-adipose-tissue macrophages. We summarize current knowledge regarding the intratissue distribution of macrophage populations and their specific association with stromal cells and discuss the mechanisms governing adipose-tissue macrophage generation and survival. We emphasize the central role of adipose-tissue macrophages in handling local lipid levels. A particular focus is placed on the recently described population of lipid-associated macrophages (LAMs), particularly abundant in adipose tissue during obesity development.},
	doi = {10.3390/ijms27041759},
	pmid = {41751896 [Indexed for MEDLINE]},
	note = {PMC12941317}
}

@ARTICLE{10.3390/ijms27041747,
	author = {Han JY and Kwon O and Lee YJ and Choi M and Lee B and Kim DK and Noh S and Cho M and Lee YM},
	title = {Comparative Anti-Obesity Potential of Cannabigerol-Dominant Cannabis sativa L. Inflorescence Extracts via Differential Regulation of Lipid Metabolism in 3T3-L1 Cells.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Obesity is a chronic metabolic disorder characterized by excessive accumulation of body fat and is a major risk factor for various diseases, including type 2 diabetes, hypertension, and cardiovascular diseases. This study investigated the anti-obesity effects of cannabigerol-dominant C. sativa inflorescence extracts (CEs) obtained using various ethanol concentrations. The extracts were analyzed by UPLC to determine their major components. Additionally, anti-obesity mechanisms of the extracts were further determined through RT-qPCR and Western blot analysis to evaluate gene and protein expression levels. A total of seven cannabinoids, including cannabigerol as a major constituent, were identified within CE. Differentiation of 3T3-L1 cells was dose-dependently inhibited by CE at all ethanol concentrations. Furthermore, the gene and protein expression levels of key adipogenic and lipogenic markers, such as PPARγ, C/EBPα, SREBP-1c, and FAS, were significantly downregulated by CE treatment. In contrast, the expression of factors involved in lipolysis and white adipose tissue browning, such as HSL, ATGL, UCP1, and PGC-1α, was markedly increased by CE treatment. These effects were enhanced in an ethanol concentration-dependent manner. In conclusion, these results demonstrate that cannabigerol-dominant C. sativa effectively mitigates obesity by suppressing adipogenesis and lipogenesis while concurrently stimulating lipolysis and white adipose tissue browning.},
	doi = {10.3390/ijms27041747},
	pmid = {41751885 [Indexed for MEDLINE]},
	note = {PMC12941217}
}

@ARTICLE{10.3390/biom16020311,
	author = {Cheng X and Li S and Zhang K and Guo Y and Li H and Li Z and Tian Y and Kang X and Liu X and Tian W},
	title = {gga-let-7c-3p Inhibits Chicken Abdominal Adipogenesis by Regulating PPARD Gene.},
	journal = {Biomolecules},
	year = {2026},
	abstract = {MicroRNAs (miRNAs) have been increasingly involved in mammalian lipid metabolism. However, their regulatory roles and molecular mechanisms in abdominal fat deposition in chicken remain largely unexplored. In this study, based on the previous miRNA transcriptome data during chicken abdominal preadipocytes' adipogenic differentiation, we explored the biological functions and regulatory mechanisms of a differentially expressed miRNA, gga-let-7c-3p, in adipogenesis. Gain- and loss-of-function assays elucidated that gga-let-7c-3p significantly decreased viability, proliferation, cell cycle progression, intracellular lipid droplet accumulation and triglyceride content, as well as the mRNA expression of proliferation- and lipid metabolism-related genes in chicken abdominal preadipocytes. Dual-luciferase reporter assay confirmed that gga-let-7c-3p could directly interact with the 3'UTR of the transcription factor-peroxisome proliferator activated the receptor delta (PPARD) gene and thus inhibited its post-transcriptional expression. The PPARD gene significantly decreased viability, proliferation, and cell cycle progression, while it increased intracellular lipid droplet accumulation and triglyceride content of chicken abdominal preadipocytes, paralleling with the mRNA expression of proliferation- and lipid metabolism-related genes. Collectively, gga-let-7c-3p could inhibit the proliferation and adipogenic differentiation of chicken abdominal preadipocytes, at least by targeting the PPARD gene. These findings reveal the regulatory mechanisms of the gga-let-7c-3p/PPARD axis in chicken abdominal adipogenesis, and could provide potential molecular markers for lean line broiler breeding.},
	doi = {10.3390/biom16020311},
	pmid = {41750379 [Indexed for MEDLINE]},
	note = {PMC12938580}
}

@ARTICLE{10.1038/s41419-026-08525-3,
	author = {Khalaji S and Venit T, Lukáčová Z and Fambri V and Shrestha R and Kaluarachchi S and Boitet M and Fagny M and Saldi G and Percipalle P},
	title = {Nuclear Myosin 1 links genomic architecture to adipose tissue remodeling, metabolic inflammation and obesity in mice.},
	journal = {Cell Death Dis},
	year = {2026},
	abstract = {Adipocyte differentiation involves a metabolic transition from oxidative phosphorylation (OXPHOS) to aerobic glycolysis, allowing preadipocytes to meet the biosynthetic and energetic demands of maturation. Here, we show that nuclear myosin 1 (NM1), a chromatin-associated actomyosin motor, known to control transcription and chromatin accessibility, is required for metabolic homeostasis during adipocyte differentiation. Integrated ATAC-seq and RNA-seq profiling of NM1-deficient mouse embryonic fibroblasts (MEFs) revealed coordinated downregulation of key adipogenic and lipid-droplet machinery genes like Cebpa, Plin2, Abhd5, Agpat2, Pink1, and altered enhancer accessibility near adipogenesis-linked transcription factors (TFs) such as Klf6, Foxo3, Smad5, and Gata4. NM1 knockout (KO) mesenchymal stem cells (MSCs) exhibited impaired differentiation potential despite enlarged adipocyte morphology. In vivo, NM1-deficient mice developed progressive visceral obesity, accompanied by transcriptional reprogramming in epididymal white adipose tissue (eWAT), including repression of mitochondrial and adipogenic pathways and activation of inflammatory networks driven by IFNG, IL33, and TNF. Cross-species network analysis highlighted conserved regulatory architecture centered on MYO1C, implicating NM1/MYO1C as key chromatin-level regulators of adipose remodeling.},
	doi = {10.1038/s41419-026-08525-3},
	pmid = {41748556 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.molcel.2026.02.001,
	author = {Long F and Ghosh A and Xu T and Ding L and Wu C and Khandelwal R, Noé F and Sun W and Dong H and Wang T and Hoffmann A and Gardeux V and Deplancke B and Abu-Nawwas L and Stefanicka P and Varga L and Ruiz JR, Blüher M and Balaz M and Sharma AK and Wolfrum C},
	title = {MEDAG functions as an A-kinase-anchoring protein in adipocytes.},
	journal = {Mol Cell},
	year = {2026},
	abstract = {Induction of catabolic adipocyte activity independent of mitochondrial uncoupling to induce energy expenditure has received increasing attention. In this study, we identified mesenteric estrogen-dependent adipogenesis gene (MEDAG), a poorly studied gene, as a promising therapeutic target for enhancing energy expenditure in adipocytes. We demonstrated that adipose MEDAG expression positively correlates with obesity and metabolic dysfunction in humans. Consistently, adipocyte-specific ablation of Medag in mice leads to increased energy expenditure, offering protection from diet-induced obesity. Mechanistically, we show that MEDAG functions as an A-kinase-anchoring protein (AKAP), which can directly regulate protein kinase A (PKA) activity through a negative feedback loop, involving direct interaction with PKA leading to MEDAG phosphorylation and consequent feedback fine-tuning of PKA activity. Specifically, the direct interaction of MEDAG with the PKA-RIIβ subunit regulates the stability of PKA-RIIβ to prevent PKA hyperactivation. These findings position MEDAG as a target for adipose energy expenditure and uncover its AKAP activity.},
	doi = {10.1016/j.molcel.2026.02.001},
	pmid = {41747731 [Indexed for MEDLINE]}
}

@ARTICLE{10.1038/s41419-026-08450-5,
	author = {Huang Y and He T and Zheng J and Chen J and Yang Z},
	title = {Circular RNAs in metabolic health: bridging the gap between molecular biology and therapy.},
	journal = {Cell Death Dis},
	year = {2026},
	abstract = {Recent advances in obesity research have shifted focus toward biological mechanisms, paralleling progress in pharmacotherapy. Fat browning-the conversion of white to brown adipocytes-emerges as a promising therapeutic strategy. Circular RNAs (circRNAs), stable non-coding RNAs with regulatory functions, are now recognized as key modulators of this process through organelle-mediated mechanisms. This review synthesizes current understanding of circRNA biogenesis and their roles in fat browning, particularly their interactions with mitochondria and endoplasmic reticulum in lipid metabolism. We highlight their capacity to encode peptides and regulate metabolic pathways, positioning circRNAs as potential precision therapeutics. While preclinical studies demonstrate mechanistic efficacy, clinical translation requires addressing delivery challenges and tissue-specific effects. This biological perspective advances obesity treatment paradigms beyond simplistic energy-balance models, mirroring the evolution seen in pharmacotherapeutic development.},
	doi = {10.1038/s41419-026-08450-5},
	pmid = {41741417 [Indexed for MEDLINE]},
	note = {PMC12988876}
}

@ARTICLE{10.1530/JOE-25-0131,
	author = {Qin L and Wu W and Su J and Wan Y and Zhang L and Fan L and Wang Y and Sun W and Zhang Q and Li Y and Zhu X},
	title = {miR-200b-3p inhibits adipose browning by targeting Prdm16.},
	journal = {J Endocrinol},
	year = {2026},
	abstract = {The expression of miR-200b-3p is correlated with obesity, but its biological function in the pathogenesis of obesity remains poorly understood. Here, we investigated the function of miR-200b-3p in white adipose browning. The C3H10T1/2 and 3T3-L1 cell lines were infected with lentiviruses carrying miR-200b-3p mimic or antisense; then, the mRNA and protein expression of adipogenic differentiation genes and brown adipose tissue-specific genes was detected. These lentiviruses were also directly injected into the inguinal white adipose tissue (iWAT) of C57BL/6 mice fed a normal chow diet or high-fat diet (HFD). Body weight, adipose tissue weight, glycolipid metabolism, and related gene expression were measured. Overexpression of miR-200b-3p impaired, whereas inhibition of miR-200b-3p improved white adipose browning both in vitro and in vivo. Mice with overexpression of miR-200b-3p in iWAT showed elevated levels of serum insulin and total cholesterol and were insulin resistant under HFD. Inhibition of miR-200b-3p in iWAT prevented mice from insulin resistance induced by HFD. Mechanistically, dual-luciferase reporter assay showed that miR-200b-3p directly inhibited Prdm16 expression in the Smad and p38Mapk signaling pathways. In conclusion, our findings suggest that miR-200b-3p regulates adipocyte browning by targeting Prdm16. This could be a potential therapeutic target for obesity.},
	doi = {10.1530/JOE-25-0131},
	pmid = {41738785 [Indexed for MEDLINE]}
}
